const body = $input.first().json.body || {};
const wa_id = body.wa_id;
const tipo = (body.tipo || 'texto').toLowerCase();

let payload = {
  recipient_type: 'individual',
  to: wa_id
};

if (tipo === 'texto' || tipo === 'text') {
  payload.type = 'text';
  payload.text = { body: body.texto || body.text || '' };
  if (body.preview_url) payload.preview_url = body.preview_url;

} else if (tipo === 'template') {
  payload.type = 'template';
  payload.template = {
    namespace: body.template_namespace || '',
    name: body.template_nome || '',
    language: {
      code: body.template_idioma || 'pt_BR',
      policy: 'deterministic'
    },
    components: body.template_componentes || []
  };

} else if (tipo === 'imagem' || tipo === 'image') {
  payload.type = 'image';
  payload.image = { id: body.midia_id || '' };
  if (body.midia_legenda) payload.image.caption = body.midia_legenda;

} else if (tipo === 'audio') {
  payload.type = 'audio';
  payload.audio = { id: body.midia_id || '' };

} else if (tipo === 'video') {
  payload.type = 'video';
  payload.video = { id: body.midia_id || '' };
  if (body.midia_legenda) payload.video.caption = body.midia_legenda;

} else if (tipo === 'documento' || tipo === 'document') {
  payload.type = 'document';
  payload.document = { id: body.midia_id || '' };
  if (body.midia_legenda) payload.document.caption = body.midia_legenda;

} else if (tipo === 'sticker') {
  payload.type = 'sticker';
  payload.sticker = { id: body.midia_id || '' };

} else if (tipo === 'interativo' || tipo === 'interactive') {
  payload.type = 'interactive';
  payload.interactive = body.interativo || body.interactive || {};

} else {
  // fallback: texto
  payload.type = 'text';
  payload.text = { body: body.texto || '' };
}

return [{ json: { payload, wa_id, tipo } }];
